diffs.replacement:
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* Default: NOIR (Signature Default) */
  --app-bg: #050505;
  --app-text: #ffffff;
  --app-accent: #e11d48; /* Standardizing on the Void Red for focus */
  --app-card: #101012;
}

[data-theme='sleek'] {
  /* LIQUID GLASS */
  --app-bg: #f1f5f9;
  --app-text: #0f172a;
  --app-accent: #2563eb;
  --app-card: rgba(255, 255, 255, 0.65);
}

[data-theme='bento'] {
  /* BENTO GRID */
  --app-bg: #f8fafc;
  --app-text: #0f172a;
  --app-accent: #2563eb;
  --app-card: #ffffff;
}

[data-theme='brutalist'] {
  /* BRUTALIST */
  --app-bg: #ffffff;
  --app-text: #000000;
  --app-accent: #000000;
  --app-card: #ffffff;
}

[data-theme='claymorphism'] {
  /* CLAYMORPHISM */
  --app-bg: #e0e7ff;
  --app-text: #312e81;
  --app-accent: #ec4899;
  --app-card: #ffffff;
}

[data-theme='monochrome-zen'] {
  /* MONOCHROME ZEN */
  --app-bg: #061a1a;
  --app-text: #ccfbf1;
  --app-accent: #14b8a6;
  --app-card: #0a2626;
}

[data-theme='y2k'] {
  /* Y2K FUTUROLOGY */
  --app-bg: #004d4d;
  --app-text: #ffffff;
  --app-accent: #ffff00;
  --app-card: #008080;
}

[data-theme='terminal'] {
  /* TERMINAL / DOS */
  --app-bg: #0d0208;
  --app-text: #00ff41;
  --app-accent: #00ff41;
  --app-card: #001100;
}

@layer utilities {
  .bg-app-bg { background-color: var(--app-bg); }
  .bg-app-card { background-color: var(--app-card); }
  .text-app-text { color: var(--app-text); }
  .text-app-accent { color: var(--app-accent); }
  .border-app-accent { border-color: var(--app-accent); }
  .bg-app-accent { background-color: var(--app-accent); }
}

/* Global Transition for Theme Switching */
html, body {
  transition: background-color 0.3s ease, color 0.3s ease;
}

/* TV & Remote Navigation: High Contrast Focus Rings */
*:focus {
  outline: none;
}

*:focus-visible {
  outline: 4px solid var(--app-accent);
  outline-offset: 4px;
  box-shadow: 0 0 20px var(--app-accent), 0 0 40px rgba(0, 0, 0, 0.5);
  transform: scale(1.02);
  transition: transform 0.2s ease, outline 0.2s ease, box-shadow 0.2s ease;
  z-index: 50;
}

/* Ensure focus works well on rounded cards */
.void-card:focus-visible, .void-button:focus-visible {
  border-color: var(--app-accent);
}

/* Prevent focus rings on touch, only show for D-pad/Keyboard */
[data-focus-visible-added] {
  transition: none;
}

{
  "name": "The Void",
  "description": "A technical noir signal reader and dark arcade for offline surveillance and decryption. Now optimized for Android TV Leanback navigation.",
  "requestFramePermissions": [
    "geolocation",
    "camera",
    "microphone"
  ]
}

import React, { useState, useEffect, useRef } from 'react';
import type { Article } from '../src/App';
import { XIcon, GlobeAltIcon, SparklesIcon, CpuChipIcon } from './icons';
import { fetchAndCacheArticleContent } from '../services/readerService';
import { soundService } from '../services/soundService';

interface ReaderViewModalProps {
    article: Article;
    onClose: () => void;
    onMarkAsRead: (articleId: string) => void;
    onOpenExternal: (url: string, id: string) => void;
}

const ReaderViewModal: React.FC<ReaderViewModalProps> = ({ article, onClose, onMarkAsRead, onOpenExternal }) => {
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [parsedContent, setParsedContent] = useState<{ title: string; content: string; category: string } | null>(null);
    const [intelBriefing, setIntelBriefing] = useState<string[] | null>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const contentRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        onMarkAsRead(article.id);
        let isMounted = true;
        const fetchContent = async () => {
            setIsLoading(true);
            setError(null);
            try {
                const result = await fetchAndCacheArticleContent(article);
                if (isMounted) setParsedContent(result);
            } catch (e) {
                if (isMounted) setError(e instanceof Error ? e.message : 'An unknown error occurred.');
            } finally {
                if (isMounted) setIsLoading(false);
            }
        };
        fetchContent();
        return () => { isMounted = false; };
    }, [article.id]);

    useEffect(() => {
        if (parsedContent && contentRef.current) {
            contentRef.current.innerHTML = parsedContent.content;
        }
    }, [parsedContent]);

    const handleLocalIntelAnalysis = () => {
        if (!parsedContent || isProcessing) return;
        setIsProcessing(true);
        soundService.playAction();

        setTimeout(() => {
            const text = contentRef.current?.innerText || "";
            // Explicitly cast the match result to an array of strings to avoid 'unknown' inference
            const sentences = (text.match(/[^.!?]+[.!?]+/g) || []) as string[];
            const tacticalWords = ['SYSTEM', 'NETWORK', 'DATA', 'SECURITY', 'GLOBAL', 'PROTOCOL', 'NODE', 'ACCESS', 'SIGNAL', 'ENCRYPT'];

            const scored = sentences.map(s => {
                let score = s.length > 40 && s.length < 150 ? 10 : 0;
                tacticalWords.forEach(w => {
                    // s is now correctly typed as string
                    if (s.toUpperCase().includes(w)) score += 5;
                });
                return { s, score };
            }).sort((a, b) => b.score - a.score);

            const results = Array.from(new Set(scored.slice(0, 3).map(i => i.s.trim())))
                .map((s: string) => s.toUpperCase());

            setIntelBriefing(results.length > 0 ? results : ["NO_CRITICAL_PATTERN_DETECTED"]);
            setIsProcessing(false);
            soundService.playCorrect();
        }, 800);
    };

    const handleExternalJump = (e: React.MouseEvent) => {
        e.preventDefault();
        onOpenExternal(article.link, article.id);
    };

    const displayCategory = parsedContent?.category || article.feedCategory || 'GENERAL';

    return (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-sm z-50 flex items-center justify-center pt-[calc(1rem+var(--safe-top))] pb-[calc(1rem+var(--safe-bottom))] px-2 md:px-6" onClick={onClose} role="dialog" aria-modal="true">
            {/* THEME WRAPPER: uses CSS variables for colors */}
            <div className="bg-app-bg w-full max-w-5xl h-full flex flex-col shadow-2xl border-4 border-app-accent relative animate-fade-in overflow-hidden" onClick={e => e.stopPropagation()}>

                <header className="bg-app-accent pt-[var(--safe-top)] relative z-20">
                    <div className="h-12 flex items-center justify-between px-1">
                        <div className="flex items-center gap-2 h-full overflow-hidden">
                            <button onClick={onClose} className="w-10 h-8 bg-app-bg border-2 border-app-accent flex items-center justify-center active:opacity-70 shrink-0">
                                <div className="w-5 h-0.5 bg-app-text shadow-[0_4px_0_var(--app-text)]" />
                            </button>
                            <div className="flex items-center gap-3 truncate">
                                <span className="text-[10px] font-black uppercase italic px-2 py-1 rounded-sm shrink-0 bg-app-bg/20 text-app-bg">
                                    {isLoading ? 'DECODING...' : displayCategory}
                                </span>
                                <h2 className="text-app-bg text-xs md:text-sm font-black uppercase tracking-widest truncate italic">
                                   SIG_DECODE: {parsedContent?.title || article.title}
                                </h2>
                            </div>
                        </div>
                        <button onClick={onClose} className="w-10 h-8 bg-app-bg border-2 border-app-accent flex items-center justify-center hover:opacity-80 transition-colors shrink-0">
                            <XIcon className="w-5 h-5 text-app-text" />
                        </button>
                    </div>
                </header>

                <div className="flex-grow overflow-y-auto bg-app-bg p-6 md:p-14 relative scrollbar-hide text-app-text">
                    <div className="absolute inset-0 pointer-events-none opacity-[0.03] cctv-overlay z-10" />

                    <div className="relative z-20">
                        {isLoading ? (
                            <div className="flex flex-col items-center justify-center h-64 gap-8">
                                <div className="p-6 border-4 border-app-accent animate-pulse">
                                    <span className="text-sm font-black uppercase tracking-[0.6em] text-app-accent italic font-mono">Decoding Signal...</span>
                                </div>
                            </div>
                        ) : error ? (
                            <div className="text-center py-24 border-4 border-red-600 bg-red-50">
                                <p className="font-black uppercase tracking-widest text-red-600 text-2xl italic mb-6">Signal Corruption</p>
                                <button onClick={handleExternalJump} className="px-12 py-5 bg-app-accent text-app-bg font-black uppercase tracking-[0.2em] italic">Access Raw Stream</button>
                            </div>
                        ) : parsedContent && (
                            <div className="max-w-none prose prose-app font-mono text-app-text prose-headings:text-app-text prose-p:text-app-text prose-p:leading-relaxed">

                                <div className="mb-12 bg-app-accent/10 border-2 border-app-accent p-8 shadow-sm relative overflow-hidden group">
                                    <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-100 transition-opacity">
                                        <CpuChipIcon className="w-10 h-10 text-app-accent" />
                                    </div>
                                    <div className="flex items-center gap-3 mb-4">
                                        <SparklesIcon className="w-5 h-5 text-app-accent animate-pulse" />
                                        <h3 className="text-xs font-black text-app-accent uppercase tracking-widest">Heuristic_Scan_Report</h3>
                                    </div>
                                    {intelBriefing ? (
                                        <div className="animate-fade-in space-y-4">
                                            {intelBriefing.map((point, idx) => (
                                                <div key={idx} className="text-xs md:text-sm leading-loose uppercase font-bold italic text-app-text border-l-4 border-app-accent pl-6">
                                                    {point}
                                                </div>
                                            ))}
                                        </div>
                                    ) : (
                                        <button 
                                            onClick={handleLocalIntelAnalysis}
                                            disabled={isProcessing}
                                            className="w-full py-4 border-2 border-dashed border-app-accent/30 text-app-accent hover:bg-app-accent hover:text-app-bg transition-all font-black uppercase italic text-xs tracking-[0.3em]"
                                        >
                                            {isProcessing ? 'Interrogating_Buffer...' : 'Initialize_Heuristic_Scan'}
                                        </button>
                                    )}
                                </div>

                                <div ref={contentRef} className="animate-fade-in" />

                                <div className="mt-24 pb-24 flex flex-col items-center border-t-2 border-app-accent/20 pt-16 mb-12">
                                    <p className="text-xs font-black text-app-accent/40 uppercase tracking-[0.5em] mb-8 italic">End of Intercept</p>
                                    <div className="flex flex-col sm:flex-row gap-6 w-full max-w-2xl">
                                        <button onClick={onClose} className="flex-1 py-6 bg-app-bg border-2 border-app-accent text-app-text font-black uppercase italic tracking-[0.2em] hover:opacity-80 transition-all text-xs md:text-sm">Close_Buffer</button>
                                        <button onClick={handleExternalJump} className="flex-1 py-6 bg-app-accent border-2 border-app-accent text-app-bg font-black uppercase italic tracking-[0.2em] hover:opacity-90 transition-all text-xs md:text-sm">Raw_Source</button>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
                <footer className="h-10 bg-app-accent/10 border-t-2 border-app-accent flex items-center px-6 justify-between shrink-0 z-20">
                    <span className="text-[10px] font-black text-app-text/60 uppercase tracking-widest font-mono">Sector_Sync: {article.source}</span>
                    <span className="text-[10px] font-black text-app-text/60 uppercase tracking-widest font-mono">Timestamp: {new Date().toLocaleTimeString()}</span>
                </footer>
            </div>
        </div>
    );
};

export default ReaderViewModal;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import MainContent from '../components/MainContent';
import type { SourceType } from '../components/AddSource';
import SettingsModal from '../components/SettingsModal';
import Sidebar from '../components/Sidebar';
import GameHubPage from '../components/GameHubPage';
import ReaderViewModal from '../components/ReaderViewModal';
import SplashScreen from '../components/SplashScreen';
import UtilityHubPage from '../components/UtilityHubPage';
import SignalStreamerPage from '../components/SignalStreamerPage';
import SurveillanceRadarPage from '../components/SurveillanceRadarPage';
import TranscoderPage from '../components/TranscoderPage';
import Base64ConverterPage from '../components/Base64ConverterPage';
import SudokuPage from '../components/SudokuPage';
import SolitairePage from '../components/SolitairePage';
import MinesweeperPage from '../components/MinesweeperPage';
import TetrisPage from '../components/TetrisPage';
import PoolGamePage from '../components/PoolGamePage';
import CipherCorePage from '../components/CipherCorePage'; 
import VoidRunnerPage from '../components/VoidRunnerPage';
import SynapseLinkPage from '../components/SynapseLinkPage';
import GridResetPage from '../components/GridResetPage';
import HangmanPage from '../components/HangmanPage';
import NeonSignalPage from '../components/NeonSignalPage';
import OrientationGuard from '../components/OrientationGuard';
import { resilientFetch } from '../services/fetch';
import { parseRssXml } from '../services/rssParser';
import { useLocalStorage } from '../hooks/useLocalStorage';
import { GlobeAltIcon, RadioIcon, XIcon, SearchIcon, VoidIcon, ControllerIcon, CpuChipIcon, MenuIcon, BoltIcon, ShieldCheckIcon } from '../components/icons';
import { soundService } from '../services/soundService';

export interface Folder { id: number; name: string; }
export interface Feed { id: number; url: string; title: string; iconUrl: string; folderId: number | null; sourceType?: SourceType; category?: string; }
export interface Article { id: string; title: string; link: string; source: string; publishedDate: Date | null; snippet: string; imageUrl: string | null; feedCategory?: string; }

export type SudokuDifficulty = 'Easy' | 'Medium' | 'Hard' | 'Expert';
export interface SudokuStats { totalWins: number; }
export interface SolitaireStats { gamesWon: number; currentStreak: number; }
export interface SolitaireSettings { drawThree: boolean; }

export type Theme = 'noir' | 'liquid-glass' | 'bento-grid' | 'brutalist' | 'claymorphism' | 'monochrome-zen' | 'y2k' | 'terminal';

export type Selection = { 
    type: 'splash' | 'all' | 'folder' | 'bookmarks' | 'search' | 'feed' | 'reddit' | 'game_hub' | 'daily_uplink' | 'grid_reset' | 'deep_sync' | 'signal_scrambler' | 'utility_hub' | 'signal_streamer' | 'surveillance_radar' | 'transcoder' | 'base64_converter' | 'sudoku' | 'solitaire' | 'minesweeper' | 'tetris' | 'pool' | 'cipher_core' | 'void_runner' | 'synapse_link' | 'hangman' | 'neon_signal'; 
    id: string | number | null; 
    query?: string;
    category?: string;
};
export type ArticleView = 'list' | 'grid' | 'featured';
export interface WidgetSettings { showWeather: boolean; showFinance: boolean; weatherLocation: string; }
export interface Settings { feeds: Feed[]; folders: Folder[]; theme: Theme; articleView: ArticleView; widgets: WidgetSettings; }

const GUEST_USER_ID = 'survivor';
const READ_ARTICLES_KEY = `void_read_articles_${GUEST_USER_ID}`;
const BOOKMARKED_ARTICLES_KEY = `void_bookmarked_articles_${GUEST_USER_ID}`;
const FEEDS_KEY = `void_feeds_${GUEST_USER_ID}`;
const FOLDERS_KEY = `void_folders_${GUEST_USER_ID}`;
const THEME_KEY = `void_theme_${GUEST_USER_ID}`;
const ARTICLE_VIEW_KEY = `void_article_view_${GUEST_USER_ID}`;
const WIDGET_SETTINGS_KEY = `void_widget_settings_${GUEST_USER_ID}`;
const UPTIME_KEY = `void_uptime_${GUEST_USER_ID}`;
const SELECTION_KEY = `void_selection_${GUEST_USER_ID}`;
const FAV_GAMES_KEY = `void_fav_games_${GUEST_USER_ID}`;
const AMBIENT_SOUND_KEY = `void_ambient_sound_${GUEST_USER_ID}`;

const FALLBACK_WORD = "FABLE";
const SECTOR_LIMIT = 7;

const TerminalView: React.FC<{ children: React.ReactNode }> = ({ children }) => (
    <div className="flex-1 flex flex-col min-w-0 relative h-full overflow-hidden">
        {children}
    </div>
);

const App: React.FC = () => {
    const [theme, setTheme] = useLocalStorage<Theme>(THEME_KEY, 'noir');
    const [articleView, setArticleView] = useLocalStorage<ArticleView>(ARTICLE_VIEW_KEY, 'list');
    const [widgetSettings, setWidgetSettings] = useLocalStorage<WidgetSettings>(WIDGET_SETTINGS_KEY, { showWeather: true, showFinance: false, weatherLocation: 'London' });
    const [folders, setFolders] = useLocalStorage<Folder[]>(FOLDERS_KEY, []);
    const [feeds, setFeeds] = useLocalStorage<Feed[]>(FEEDS_KEY, []);
    const [readArticleIds, setReadArticleIds] = useLocalStorage<Set<string>>(READ_ARTICLES_KEY, () => new Set());
    const [bookmarkedArticleIds, setBookmarkedArticleIds] = useLocalStorage<Set<string>>(BOOKMARKED_ARTICLES_KEY, () => new Set());
    const [favoriteGameIds, setFavoriteGameIds] = useLocalStorage<Set<string>>(FAV_GAMES_KEY, () => new Set());
    const [ambientEnabled, setAmbientEnabled] = useLocalStorage<boolean>(AMBIENT_SOUND_KEY, false);

    const [uptime, setUptime] = useLocalStorage<number>(UPTIME_KEY, 25);
    const [selection, setSelection] = useLocalStorage<Selection>(SELECTION_KEY, { type: 'splash', id: null });

    const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const [readerArticle, setReaderArticle] = useState<Article | null>(null);
    const [prefetchedArticles, setPrefetchedArticles] = useState<Article[]>([]);
    const [isDecoding, setIsDecoding] = useState(false);
    const [lastRefresh, setLastRefresh] = useState(() => Date.now());

    const [cipherData, setCipherData] = useState<{ archiveMap: { date: string; word: string; label: string }[]; isSynced: boolean; loading: boolean }>({
        archiveMap: [],
        isSynced: false,
        loading: true
    });

    useEffect(() => {
        const doc = document.documentElement;
        const dataThemeMap: Record<Theme, string> = {
            'noir': 'noir',
            'terminal': 'terminal',
            'bento': 'bento',
            'liquid-glass': 'sleek',
            'brutalist': 'brutalist',
            'claymorphism': 'claymorphism',
            'monochrome-zen': 'monochrome-zen',
            'y2k': 'y2k',
            'bento-grid': 'bento'
        };
        doc.setAttribute('data-theme', dataThemeMap[theme] || 'noir');

        const themeClasses = ['theme-liquid-glass', 'theme-bento-grid', 'theme-brutalist', 'theme-claymorphism', 'theme-monochrome-zen', 'theme-y2k', 'theme-terminal'];
        themeClasses.forEach(c => doc.classList.remove(c));
        if (theme !== 'noir') {
            doc.classList.add(`theme-${theme}`);
        }

        soundService.setAmbient(ambientEnabled, theme);
    }, [ambientEnabled, theme]);

    const isGameActive = useMemo(() => {
        const gameTypes = ['sudoku', 'solitaire', 'minesweeper', 'tetris', 'pool', 'cipher_core', 'void_runner', 'synapse_link', 'grid_reset', 'hangman', 'neon_signal'];
        return gameTypes.includes(selection.type);
    }, [selection.type]);

    const isUtilityActive = useMemo(() => {
        const utilTypes = ['utility_hub', 'signal_streamer', 'surveillance_radar', 'transcoder', 'base64_converter'];
        return utilTypes.includes(selection.type);
    }, [selection.type]);

    const handleToggleTheme = useCallback(() => {
        const themes: Theme[] = ['noir', 'liquid-glass', 'bento-grid', 'brutalist', 'claymorphism', 'monochrome-zen', 'y2k', 'terminal'];
        const nextIndex = (themes.indexOf(theme) + 1) % themes.length;
        setTheme(themes[nextIndex]);
    }, [theme, setTheme]);

    const handleResetSystem = useCallback(() => {
        soundService.playWrong();
        setFeeds([]);
        setFolders([]);
        setReadArticleIds(new Set());
        setBookmarkedArticleIds(new Set());
        setSelection({ type: 'all', id: null });
        setIsSettingsModalOpen(false);
    }, [setFeeds, setFolders, setReadArticleIds, setBookmarkedArticleIds, setSelection]);

    const handleAddSource = useCallback(async (url: string, type: SourceType) => {
        setFeeds(prev => [...prev, { 
            id: Date.now() + Math.random(), 
            url, title: 'New Signal', 
            iconUrl: `https://www.google.com/s2/favicons?sz=32&domain_url=${new URL(url).hostname}`, 
            folderId: null, sourceType: type 
        }]);
    }, [setFeeds]);

    const prefetchCipherFrequency = useCallback(async () => {
        const results = new Map<string, string>();
        try {
            const response = await resilientFetch('https://screenrant.com/wordle-history/', { timeout: 12000 });
            if (response.ok) {
                const html = await response.text();
                const doc = new DOMParser().parseFromString(html, 'text/html');
                const tables = doc.querySelectorAll('table');
                tables.forEach(table => {
                    table.querySelectorAll('tr').forEach(row => {
                        const cells = row.querySelectorAll('td');
                        if (cells.length >= 2) {
                            const dateRaw = cells[0].textContent?.trim() || "";
                            const wordRaw = cells[1].textContent?.trim().toUpperCase() || "";
                            if (/^[A-Z]{5}$/.test(wordRaw)) {
                                try {
                                    const d = new Date(dateRaw);
                                    if (!isNaN(d.getTime())) results.set(d.toISOString().split('T')[0], wordRaw);
                                } catch (e) {}
                            }
                        }
                    });
                });
            }
        } catch (e) {}

        const finalMap = Array.from({ length: SECTOR_LIMIT }, (_, i) => {
            const d = new Date(); d.setDate(d.getDate() - i);
            const iso = d.toISOString().split('T')[0];
            let word = results.get(iso) || FALLBACK_WORD;
            return { date: iso, word, label: i === 0 ? "TODAY" : `T-${i}` };
        });
        setCipherData({ archiveMap: finalMap, isSynced: results.size > 0, loading: false });
    }, []);

    const prefetchContentFrequencies = useCallback(async () => {
        if (feeds.length === 0) return;
        setIsDecoding(true);
        const topFeeds = feeds.slice(0, 3);
        const promises = topFeeds.map(feed => 
            resilientFetch(feed.url, { timeout: 8000 })
                .then(res => res.text())
                .then(xml => parseRssXml(xml, feed.title, feed.url))
                .catch(() => [])
        );
        try {
            const results = await Promise.all(promises);
            const all = results.flat().sort((a, b) => (b.publishedDate?.getTime() || 0) - (a.publishedDate?.getTime() || 0));
            setPrefetchedArticles(Array.from(new Map(all.map(a => [a.id, a])).values()));
        } finally { setIsDecoding(false); }
    }, [feeds]);

    useEffect(() => {
        prefetchCipherFrequency();
        if (selection.type === 'splash' && feeds.length > 0) prefetchContentFrequencies();
    }, [prefetchCipherFrequency, prefetchContentFrequencies, selection.type, feeds.length]);

    const updateSelection = useCallback((newSel: Selection, replace: boolean = false) => {
        setSelection(newSel);
        if (replace) window.history.replaceState({ selection: newSel }, '');
        else window.history.pushState({ selection: newSel }, '');
        setIsSidebarOpen(false);
    }, [setSelection]);

    if (selection.type === 'splash') {
        return <SplashScreen onEnterFeeds={() => updateSelection({ type: 'all', id: null })} onEnterArcade={() => updateSelection({ type: 'game_hub', id: null })} isDecoding={isDecoding} onReset={handleResetSystem} />;
    }

    // Shield sidebar when in games
    const hideMenuTrigger = isGameActive || selection.type === 'game_hub';

    return (
        <div className="h-screen w-full font-sans text-sm relative flex flex-col overflow-hidden bg-app-bg text-app-text transition-colors duration-300">
            <header className="fixed top-0 left-0 right-0 z-[60] bg-black border-b border-white/10 pt-[var(--safe-top)] shrink-0">
                <div className="h-11 md:h-12 flex items-center px-2 md:px-8 justify-between">
                    <div className="flex items-center h-full gap-2 md:gap-3 overflow-x-auto scrollbar-hide">
