@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* Default: NOIR (Signature Default) */
  --app-bg: #050505;
  --app-text: #ffffff;
  --app-accent: #e11d48; /* Void Red */
  --app-card: #101012;
}

[data-theme='sleek'] {
  --app-bg: #f1f5f9;
  --app-text: #0f172a;
  --app-accent: #2563eb;
  --app-card: rgba(255, 255, 255, 0.65);
}

[data-theme='bento'] {
  --app-bg: #f8fafc;
  --app-text: #0f172a;
  --app-accent: #2563eb;
