}

@layer utilities {
  .bg-app-bg { background-color: var(--app-bg); }
  .bg-app-card { background-color: var(--app-card); }
  .text-app-text { color: var(--app-text); }
  .text-app-accent { color: var(--app-accent); }
  .border-app-accent { border-color: var(--app-accent); }
  .bg-app-accent { background-color: var(--app-accent); }

  /* Procedural Loader */
  .void-spinner {
    border-right-color: transparent;
    border-bottom-color: transparent;
  }
}

html, body {
  transition: background-color 0.3s ease, color 0.3s ease;
}

/* TV & Remote Navigation: Ultra High Contrast Focus Rings */
*:focus {
  outline: none;
}

*:focus-visible, button:focus, [role="button"]:focus, a:focus {
  outline: 4px solid #fff !important;
  outline-offset: 4px !important;
  box-shadow: 0 0 0 8px var(--app-accent), 0 0 80px var(--app-accent) !important;
  transform: scale(1.08) !important;
  transition: transform 0.1s cubic-bezier(0.175, 0.885, 0.32, 1.275), outline 0.1s ease, box-shadow 0.1s ease !important;
  z-index: 100 !important;
  position: relative;
}

[data-theme='sleek'] *:focus-visible, 
[data-theme='bento'] *:focus-visible,
[data-theme='sleek'] button:focus,
[data-theme='bento'] button:focus {
  outline: 4px solid var(--app-accent) !important;
  box-shadow: 0 0 0 8px rgba(255,255,255,0.9), 0 20px 40px rgba(0,0,0,0.2) !important;
}

.void-card:focus-visible, .void-button:focus-visible, .void-button:focus {
  border-color: #fff !important;
}

/* Ensure selected state is also visually distinct even without focus */
.selected-category {
    background-color: var(--app-accent) !important;
    border-color: #fff !important;
    color: #fff !important;
    box-shadow: 0 0 20px var(--app-accent) !important;
}

/* Scrollbar Hide Utility */
.scrollbar-hide::-webkit-scrollbar {
  display: none;
}
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

import React, { useState, useEffect, useCallback, useMemo, useRef, useLayoutEffect } from 'react';
