@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* Default: NOIR (Signature Default) */
  --app-bg: #050505;
  --app-text: #ffffff;
  --app-accent: #3b82f6; /* Modern Blue */
  --app-card: #121214;
  --halo-color: rgba(255, 255, 255, 0.5);
}

[data-theme='sleek'] {
  --app-bg: #f8fafc;
  --app-text: #0f172a;
  --app-accent: #2563eb;
  --app-card: #ffffff;
  --halo-color: rgba(37, 99, 235, 0.3);
}

@layer utilities {
  .bg-app-bg { background-color: var(--app-bg); }
  .bg-app-card { background-color: var(--app-card); }
  .text-app-text { color: var(--app-text); }
  .text-app-accent { color: var(--app-accent); }
  .border-app-accent { border-color: var(--app-accent); }
  .bg-app-accent { background-color: var(--app-accent); }
}

html, body {
  transition: background-color 0.4s ease, color 0.4s ease;
  background-color: var(--app-bg);
  color: var(--app-text);
}

/* Modern Cinematic Focus Engine */
*:focus {
  outline: none;
}

/* Base transition for all interactive elements */
button, a, input, [role="button"], .void-card {
  transition: transform 0.25s cubic-bezier(0.2, 0.8, 0.2, 1), 
              box-shadow 0.25s ease, 
              background-color 0.25s ease, 
              color 0.2s ease;
}

/* The "HALO" Effect */
*:focus-visible, 
button:focus:not(:active), 
[role="button"]:focus:not(:active),
.focusable-tile:focus {
  transform: scale(1.06) translateY(-2px) !important;
  background-color: #ffffff !important;
  color: #000000 !important;
  box-shadow: 0 0 0 4px #ffffff, 
              0 20px 40px rgba(0, 0, 0, 0.4), 
              0 0 30px var(--halo-color) !important;
  z-index: 50 !important;
  border-color: transparent !important;
}

/* Invert icons inside focused buttons */
*:focus-visible svg,
button:focus svg {
  color: #000000 !important;
  stroke: #000000 !important;
}

/* Subtle pulse for the focused halo */
@keyframes halo-breath {
  0%, 100% { box-shadow: 0 0 0 4px #ffffff, 0 20px 40px rgba(0,0,0,0.4), 0 0 20px var(--halo-color); }
  50% { box-shadow: 0 0 0 6px #ffffff, 0 25px 50px rgba(0,0,0,0.5), 0 0 40px var(--halo-color); }
}

*:focus-visible {
  animation: halo-breath 2s infinite ease-in-out;
}

/* Search Input Specifics */
input:focus {
  background-color: #ffffff !important;
  color: #000000 !important;
  animation: none !important;
}

/* Scrollbar Hide Utility */
.scrollbar-hide::-webkit-scrollbar {
  display: none;
}
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.cctv-overlay {
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.1) 50%), 
              repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(255, 255, 255, 0.02) 2px, rgba(255, 255, 255, 0.02) 4px);
  pointer-events: none;
}

