                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
                        {rollingNews.map(article => (
                            <MagazineArticleListItem 
                                key={article.id} 
                                article={article} 
                                onMarkAsRead={() => onMarkAsRead(article.id)} 
