@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* THEME 1: NOIR (Signature Default) */
  --app-bg: #050505;
  --app-text: #ffffff;
  --app-accent: #e11d48; /* Corrected to signature Red */
  --app-card: #101012;
  --halo-color: rgba(225, 29, 72, 0.3);
  --void-radius: 1.25rem;
}

[data-theme='sleek'] {
  --app-bg: #f8fafc;
  --app-text: #0f172a;
  --app-accent: #2563eb;
  --app-card: #ffffff;
  --halo-color: rgba(37, 99, 235, 0.2);
  --void-radius: 1.75rem;
}

[data-theme='terminal'] {
  --app-bg: #000000;
  --app-text: #33ff33;
  --app-accent: #33ff33;
  --app-card: #000000;
  --halo-color: rgba(51, 255, 51, 0.4);
  --void-radius: 0.5rem;
}

[data-theme='brutalist'] {
  --app-bg: #ffffff;
  --app-text: #000000;
  --app-accent: #000000;
  --app-card: #ffffff;
  --halo-color: rgba(0, 0, 0, 0.1);
  --void-radius: 0px;
}

@layer utilities {
  .bg-app-bg { background-color: var(--app-bg); }
  .bg-app-card { background-color: var(--app-card); }
  .text-app-text { color: var(--app-text); }
  .text-app-accent { color: var(--app-accent); }
  .border-app-accent { border-color: var(--app-accent); }
  .bg-app-accent { background-color: var(--app-accent); }
}

html, body {
  transition: background-color 0.6s cubic-bezier(0.4, 0, 0.2, 1), color 0.6s ease;
  background-color: var(--app-bg);
  color: var(--app-text);
  height: 100dvh;
  width: 100%;
}

/* Modern Cinematic Focus Engine */
*:focus {
  outline: none;
}

button, a, input, [role="button"], .void-card {
  transition: transform 0.2s cubic-bezier(0.2, 0.8, 0.2, 1), 
              box-shadow 0.2s ease, 
              background-color 0.2s ease, 
              color 0.1s ease,
              border-color 0.4s ease;
}

.nav-underline {
  position: absolute;
  bottom: 0;
  left: 50%;
  width: 0;
  height: 3px;
  background: var(--app-accent);
  transition: all 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
  transform: translateX(-50%);
  border-radius: 4px;
}

*:focus-visible .nav-underline,
button:focus .nav-underline {
  width: 80%;
  box-shadow: 0 0 15px var(--app-accent);
}

*:focus-visible, button:focus {
  font-weight: 900 !important;
}

.main-content-area button:focus, 
.main-content-area .void-card:focus {
  transform: scale(1.05) translateY(-4px) !important;
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.6), 0 0 30px var(--halo-color) !important;
  z-index: 50 !important;
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.cctv-overlay {
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.1) 50%), 
              repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(255, 255, 255, 0.02) 2px, rgba(255, 255, 255, 0.02) 4px);
  pointer-events: none;
}

