            .particle {
                position: absolute;
                background: var(--app-accent);
                border-radius: 50%;
                filter: blur(1px);
                animation: float linear infinite;
            }
        `}</style>
        {[...Array(20)].map((_, i) => (
            <div 
                key={i} 
                className="particle"
                style={{
                    width: `${Math.random() * 4 + 1}px`,
                    height: `${Math.random() * 4 + 1}px`,
                    left: `${Math.random() * 100}%`,
                    animationDuration: `${Math.random() * 8 + 6}s`,
                    animationDelay: `${Math.random() * 5}s`,
                    opacity: Math.random() * 0.3
                }}
            />
        ))}
    </div>
);

const SplashScreen: React.FC<SplashScreenProps> = ({ theme, onEnterFeeds, onEnterArcade, onToggleTheme, isDecoding, onReset }) => {
    const [loadingProgress, setLoadingProgress] = useState(0);
    const [currentMessage, setCurrentMessage] = useState(BOOT_MESSAGES[0]);
    const [isBootComplete, setIsBootComplete] = useState(false);
    const [showWipeConfirm, setShowWipeConfirm] = useState(false);
    const [breached, setBreached] = useState(false);
    const lastPingRef = useRef(0);
    const mainButtonRef = useRef<HTMLButtonElement>(null);

    const themeMeta = THEME_VERSIONS[theme];

    useEffect(() => {
        if (isBootComplete && breached && mainButtonRef.current) {
            mainButtonRef.current.focus();
        }
    }, [isBootComplete, breached]);

    useEffect(() => {
        const totalDuration = 2000;
        const intervalTime = 20;
        const startTime = Date.now();

        const timer = setInterval(() => {
            const elapsed = Date.now() - startTime;
            const progress = Math.min(100, (elapsed / totalDuration) * 100);

            setLoadingProgress(progress);

            if (progress >= 100) {
                clearInterval(timer);
                setIsBootComplete(true);
                soundService.playBootComplete();
                setTimeout(() => setBreached(true), 200);
            }

            const currentThresh = Math.floor(progress / 20);
            if (currentThresh > lastPingRef.current) {
                soundService.playBootPing(progress);
                lastPingRef.current = currentThresh;
            }

            const msgIndex = Math.floor((progress / 100) * BOOT_MESSAGES.length);
            setCurrentMessage(BOOT_MESSAGES[msgIndex] || BOOT_MESSAGES[BOOT_MESSAGES.length - 1]);
        }, intervalTime);

        return () => clearInterval(timer);
    }, [isDecoding]);

    const handleSystemWipe = () => {
        if (onReset) {
            onReset();
            setShowWipeConfirm(false);
        } else {
            localStorage.clear();
            const req = indexedDB.deleteDatabase('SeeMoreCache');
            req.onsuccess = () => window.location.reload();
            req.onerror = () => window.location.reload();
            req.onblocked = () => window.location.reload();
        }
    };

    return (
        <div className="fixed inset-0 z-[100] transition-all duration-[800ms] flex flex-col items-center justify-center overflow-hidden font-mono bg-app-bg text-app-text">

            <style>{`
                @keyframes dimension-shift {
                    0% { clip-path: circle(0% at 50% 50%); }
                    100% { clip-path: circle(150% at 50% 50%); }
                }
                .dimension-breach {
                    animation: dimension-shift 2.5s cubic-bezier(0.23, 1, 0.32, 1) forwards;
                }
                .glass-reveal {
                    background: var(--app-card);
                    backdrop-filter: blur(${themeMeta.refraction});
                    -webkit-backdrop-filter: blur(${themeMeta.refraction});
                    border: 1px solid var(--app-accent);
                    box-shadow: 0 40px 100px rgba(0,0,0,0.2);
                    width: 100%;
                    border-radius: var(--void-radius);
                    position: relative;
                }
                .glass-reveal::after {
                    content: '';
                    position: absolute;
                    inset: 0;
                    background: linear-gradient(135deg, rgba(255,255,255,0.1) 0%, transparent 40%, rgba(255,255,255,0.05) 50%, transparent 60%);
                    pointer-events: none;
                }
                .theme-terminal .cctv-overlay { opacity: 0.15; }
                .theme-brutalist .glass-reveal { border-width: 4px; box-shadow: 10px 10px 0 black; backdrop-filter: none; }
                .theme-comic .glass-reveal { border-width: 4px; border-color: #1a1a1a; box-shadow: 8px 8px 0 #1a1a1a; backdrop-filter: none; }
                .footer-button:focus {
                    transform: scale(1.1) !important;
                    background: var(--app-card) !important;
                    color: var(--app-text) !important;
                    border-color: var(--app-accent) !important;
                    box-shadow: 0 0 40px var(--halo-color) !important;
                    z-index: 60;
                }
                .refraction-overlay {
                    position: absolute;
                    inset: 0;
                    backdrop-filter: blur(${parseInt(themeMeta.refraction) / 2}px);
                    mask-image: radial-gradient(circle at 50% 50%, transparent 20%, black 80%);
                    pointer-events: none;
                    z-index: 5;
                }
            `}</style>

            <div className="refraction-overlay transition-all duration-1000" />

            {!breached && <TechnicalBlueprint progress={loadingProgress} />}
            {breached && <VoidParticles />}

            <div className={`absolute inset-0 z-10 pointer-events-none transition-opacity duration-1000 ${breached ? 'opacity-0' : 'opacity-30 cctv-overlay'}`} />

            <div className={`relative z-20 w-full max-w-lg flex flex-col items-center text-center py-6 transition-all duration-1000 ${breached ? 'translate-y-0 scale-100' : 'translate-y-4 scale-95'}`}>

                <div className="mb-8 landscape:mb-4 group relative">
                    <div className="absolute inset-[-20px] blur-[40px] md:blur-[60px] transition-all duration-1000 rounded-full opacity-30" style={{ backgroundColor: 'var(--app-accent)' }} />

                    <div className={`relative p-8 md:p-10 rounded-full transition-all duration-1000 border-4 bg-app-card shadow-[0_0_60px_rgba(0,0,0,0.3)]`} style={{ borderColor: 'var(--app-accent)' }}>
                        <VoidIcon className="w-16 h-16 md:w-24 md:h-24 transition-colors duration-1000 text-app-text" />
                    </div>
                </div>

                <div className="mb-8 landscape:mb-4 flex flex-col items-center">
                    <h1 className="text-5xl md:text-8xl font-black italic uppercase tracking-tighter mb-4 transition-colors duration-1000 text-app-text">
                        THE VOID
                    </h1>

                    <div className="flex items-center justify-center gap-3">
                        <div className="h-px w-12 transition-colors duration-1000" style={{ backgroundColor: 'var(--app-accent)' }}></div>
                        <p className="font-bold uppercase tracking-[0.6em] text-[8px] md:text-[10px] transition-colors duration-1000" style={{ color: 'var(--app-accent)' }}>
                            {themeMeta.v}_{themeMeta.tag}
                        </p>
                        <div className="h-px w-12 transition-colors duration-1000" style={{ backgroundColor: 'var(--app-accent)' }}></div>
                    </div>
                </div>

                {!isBootComplete ? (
                    <div className="w-full space-y-4 landscape:space-y-2 max-w-[280px] mx-auto animate-fade-in">
                        <div className="w-full h-1 bg-zinc-900 border border-white/5 rounded-full overflow-hidden shadow-inner">
                            <div 
                                className="h-full bg-app-accent shadow-[0_0_15px_var(--app-accent)] transition-all duration-200"
                                style={{ width: `${loadingProgress}%` }}
                            />
                        </div>
                        <div className="flex justify-between items-center text-[8px] font-black text-zinc-500 italic tracking-[0.2em]">
                            <span className="truncate max-w-[80%] uppercase">{currentMessage}</span>
                            <span>{Math.floor(loadingProgress)}%</span>
                        </div>
                    </div>
                ) : (
                    <div className="w-full flex flex-col gap-5 landscape:gap-3 animate-fade-in max-w-md items-center main-content-area px-4">
                        <div className="glass-reveal p-1 shadow-2xl overflow-hidden w-full">
                            <button 
                                ref={mainButtonRef}
                                onClick={onEnterFeeds}
                                className="group relative w-full py-5 bg-app-text text-app-bg font-black uppercase italic text-base rounded-void shadow-xl transition-all active:scale-95 flex items-center justify-center gap-4 border-2 border-app-bg outline-none focus:ring-8 focus:ring-app-accent"
                            >
                                <ListIcon className="w-6 h-6" />
                                <span>RECON_INTELLIGENCE</span>
                            </button>
                        </div>

                        <button 
                            onClick={onEnterArcade}
                            className="group w-full py-5 bg-app-card border-2 border-app-accent text-app-text font-black uppercase italic text-base rounded-void hover:bg-app-bg transition-all active:scale-95 flex items-center justify-center gap-4 shadow-sm outline-none focus:ring-8 focus:ring-app-accent"
                        >
                            <ControllerIcon className="w-6 h-6" />
                            <span>ARCADE_QUICK_ACCESS</span>
                        </button>
                    </div>
                )}
            </div>

            {isBootComplete && (
                <div className="fixed bottom-0 left-0 right-0 p-8 md:p-12 pb-[calc(2.5rem+var(--safe-bottom))] flex justify-between items-center z-50 pointer-events-none">
                    <button 
                        onClick={onToggleTheme}
                        className="footer-button group inline-flex items-center gap-3 text-zinc-500 hover:text-app-accent transition-all py-3 px-6 bg-app-card/10 backdrop-blur-md rounded-full border border-white/5 uppercase text-[10px] font-black italic tracking-widest active:scale-95 outline-none focus:ring-8 focus:ring-app-accent pointer-events-auto shadow-xl"
                    >
                        <PaletteIcon className="w-4 h-4" />
                        <span>UI CHANGE</span>
                    </button>

                    <button 
                        onClick={() => setShowWipeConfirm(true)}
                        className="footer-button group inline-flex items-center justify-center gap-3 text-zinc-500 hover:text-red-500 transition-all py-3 px-6 bg-app-card/10 backdrop-blur-md rounded-full border border-white/5 uppercase text-[10px] font-black italic tracking-widest active:scale-95 outline-none focus:ring-8 focus:ring-red-500 pointer-events-auto shadow-xl"
                    >
                        <TrashIcon className="w-4 h-4" />
                        <span>PURGE</span>
                    </button>
                </div>
            )}

            {showWipeConfirm && (
                <div className="fixed inset-0 z-[110] bg-black/95 backdrop-blur-md flex items-center justify-center p-6 animate-fade-in">
                    <div className="bg-app-card border-2 border-app-accent shadow-[0_30px_100px_rgba(0,0,0,0.2)] w-full max-w-sm relative overflow-hidden flex flex-col rounded-[2rem]">
                        <header className="h-12 bg-app-accent flex items-center justify-between px-4">
                            <div className="flex items-center gap-3">
                                <ExclamationTriangleIcon className="w-4 h-4 text-app-bg" />
                                <h2 className="text-app-bg text-[10px] font-black uppercase tracking-[0.2em] italic">SYSTEM_PURGE.DAT</h2>
                            </div>
                            <button onClick={() => { soundService.playClick(); setShowWipeConfirm(false); }} className="text-app-bg hover:opacity-70 outline-none focus:ring-2 focus:ring-white">
                                <XIcon className="w-5 h-5" />
                            </button>
                        </header>
                        <div className="p-8 text-center space-y-6">
                            <p className="text-xs text-app-text leading-relaxed uppercase font-bold tracking-tight px-4 italic">
                                Operator, committing to a <span className="text-app-accent">System Wipe</span> will permanently erase all crystalline cache data, discovered signals, and mission records.
                            </p>
                        </div>
                        <footer className="p-5 flex gap-3 bg-app-bg/20 border-t border-white/5">
                            <button onClick={() => { soundService.playClick(); setShowWipeConfirm(false); }} className="flex-1 py-4 bg-app-card border border-app-accent/20 rounded-xl text-[10px] font-black uppercase italic text-zinc-500 outline-none focus:ring-4 focus:ring-app-accent">Abort</button>
                            <button onClick={handleSystemWipe} className="flex-1 py-4 bg-red-600 text-white rounded-xl text-[10px] font-black uppercase italic shadow-lg active:scale-95 outline-none focus:ring-4 focus:ring-red-900">Confirm Purge</button>
