@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* THEME 1: NOIR (Signature Default) */
  --app-bg: #050505;
  --app-text: #ffffff;
  --app-accent: #e11d48;
  --app-card: #101012;
  --halo-color: rgba(225, 29, 72, 0.3);
  --void-radius: 1.25rem;
  --comic-ink: #1a1a1a;
}

[data-theme='sleek'] {
  --app-bg: #f8fafc;
  --app-text: #0f172a;
  --app-accent: #2563eb;
  --app-card: #ffffff;
  --halo-color: rgba(37, 99, 235, 0.2);
  --void-radius: 1.75rem;
}

[data-theme='terminal'] {
  --app-bg: #000000;
  --app-text: #33ff33;
  --app-accent: #33ff33;
  --app-card: #000000;
  --halo-color: rgba(51, 255, 51, 0.4);
  --void-radius: 0.5rem;
}

[data-theme='brutalist'] {
  --app-bg: #ffffff;
  --app-text: #000000;
  --app-accent: #000000;
  --app-card: #ffffff;
  --halo-color: rgba(0, 0, 0, 0.1);
  --void-radius: 0px;
}

[data-theme='comic'] {
  --app-bg: #fffceb;
  --app-text: #1a1a1a;
  --app-accent: #ff3e3e;
  --app-card: #ffffff;
  --halo-color: rgba(255, 62, 62, 0.2);
  --void-radius: 0px;
}

@layer utilities {
  .bg-app-bg { background-color: var(--app-bg); }
  .bg-app-card { background-color: var(--app-card); }
  .text-app-text { color: var(--app-text); }
  .text-app-accent { color: var(--app-accent); }
  .border-app-accent { border-color: var(--app-accent); }
  .bg-app-accent { background-color: var(--app-accent); }
}

html, body {
  transition: background-color 0.6s cubic-bezier(0.4, 0, 0.2, 1), color 0.6s ease;
  background-color: var(--app-bg);
  color: var(--app-text);
  height: 100dvh;
  width: 100%;
}

/* --- GLOBAL COMIC ENGINE --- */
.theme-comic body {
  background-image: radial-gradient(#00000008 1.5px, transparent 0);
  background-size: 15px 15px;
}

.theme-comic h1, .theme-comic h2, .theme-comic h3, .theme-comic button {
  font-weight: 900 !important;
  text-transform: uppercase !important;
  letter-spacing: -0.02em !important;
}

/* Force hard borders on everything in Comic mode */
.theme-comic .void-card, 
.theme-comic button:not(.footer-button), 
.theme-comic aside, 
.theme-comic header,
.theme-comic .cabinet-grid > div,
.theme-comic .main-content-area button,
.theme-comic input {
  border: 3px solid var(--comic-ink) !important;
  box-shadow: 6px 6px 0px var(--comic-ink) !important;
  border-radius: 0px !important;
}

.theme-comic .bg-zinc-950,
.theme-comic .bg-zinc-900,
.theme-comic .bg-black,
.theme-comic .bg-void-950,
.theme-comic .bg-void-900 {
  background-color: var(--app-bg) !important;
}

.theme-comic .bg-zinc-800,
.theme-comic .bg-app-card {
  background-color: var(--app-card) !important;
}

.theme-comic .text-zinc-400,
.theme-comic .text-zinc-500,
.theme-comic .text-zinc-600 {
  color: var(--comic-ink) !important;
  opacity: 0.7;
}

/* Ben-Day Dots for all imagery */
.theme-comic img, .theme-comic canvas {
  filter: contrast(1.1) saturate(1.2);
  mix-blend-mode: multiply;
}

.theme-comic .image-halftone-overlay, 
.theme-comic [style*="background-image"],
.theme-comic .relative.aspect-square,
.theme-comic .relative.aspect-video {
  position: relative;
}

.theme-comic .image-halftone-overlay::after,
.theme-comic .relative.aspect-square::after,
.theme-comic .relative.aspect-video::after {
  content: "";
  position: absolute;
  inset: 0;
  background-image: radial-gradient(circle, #000 0.8px, transparent 0.8px);
  background-size: 4px 4px;
  opacity: 0.12;
  pointer-events: none;
  z-index: 10;
}

/* Kinetic Comic Transitions */
.theme-comic button:active {
  transform: translate(3px, 3px) !important;
  box-shadow: 2px 2px 0px var(--comic-ink) !important;
}

/* --- FOCUS ENGINE OVERRIDES --- */
*:focus {
  outline: none;
}

.theme-comic button:focus, 
.theme-comic .void-card:focus {
  border-color: var(--app-accent) !important;
  transform: rotate(-1deg) scale(1.02) !important;
  z-index: 50 !important;
}

.nav-underline {
  position: absolute;
  bottom: 0;
  left: 50%;
  width: 0;
  height: 3px;
  background: var(--app-accent);
  transition: all 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
  transform: translateX(-50%);
  border-radius: 4px;
}

*:focus-visible .nav-underline,
button:focus .nav-underline {
  width: 80%;
  box-shadow: 0 0 15px var(--app-accent);
}

.scrollbar-hide::-webkit-scrollbar { display: none; }
.scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }

.cctv-overlay {
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.1) 50%), 
              repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(255, 255, 255, 0.02) 2px, rgba(255, 255, 255, 0.02) 4px);
  pointer-events: none;
}

