import Tooltip from './Tooltip';

type GameState = 'LOADING' | 'BOOTING' | 'IDLE' | 'PLAYING' | 'ERROR' | 'WON' | 'LOST';

interface Cell {
  value: number | null;
  isPrefilled: boolean;
  isCorrect?: boolean;
  notes: number[]; 
  isError: boolean;
}

type Grid = Cell[][];

const MISTAKE_LIMIT = 3;

