}

/* Asymmetric Comic Layout */
.theme-comic .cabinet-grid > div:nth-child(odd) { transform: rotate(-1.5deg); }
.theme-comic .cabinet-grid > div:nth-child(even) { transform: rotate(1.2deg); }
.theme-comic .cabinet-grid > div:nth-child(3n) { transform: rotate(0.8deg) translateY(-10px); }

.theme-comic .article-list-grid > div:nth-child(odd) { transform: rotate(0.5deg); }
.theme-comic .article-list-grid > div:nth-child(even) { transform: rotate(-0.5deg); }

.theme-comic button:focus {
  transform: scale(1.05) rotate(0deg) !important;
  border-color: var(--app-accent) !important;
  background-color: var(--app-accent) !important;
  color: white !important;
  z-index: 50;
}

/* Ben-Day Dots for all imagery */
.theme-comic img {
  filter: contrast(1.1) saturate(1.4);
