                <div className="relative">
                    {!isSearchActive ? (
                        <button 
                            onClick={() => setIsSearchActive(true)}
                            className="flex items-center gap-3 px-8 h-11 bg-app-card border-4 border-zinc-950 text-xs font-black uppercase italic text-zinc-500 hover:text-app-text transition-all shadow-[6px_6px_0_black] active:translate-x-1 active:translate-y-1 outline-none"
