                                    className="w-48 md:w-72 bg-white border-4 border-zinc-950 py-3 pl-12 pr-6 text-sm uppercase font-black tracking-widest outline-none text-black transition-all shadow-[6px_6px_0_black]" 
                                />
                            </div>
                            <button type="button" onClick={() => { setIsSearchActive(false); setSearchQuery(''); }} className="p-3 text-zinc-500 hover:text-app-text"><XIcon className="w-5 h-5"/></button>
                        </form>
                    )}
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={onRefresh}
                        className="p-3 h-11 w-11 flex items-center justify-center bg-app-card border-4 border-zinc-950 text-zinc-500 hover:text-app-text transition-all shadow-[4px_4px_0_black] active:translate-x-1 active:translate-y-1"
                        title="Refresh Signals"
