            {!breached && <TechnicalBlueprint progress={loadingProgress} />}

            <div className={`relative z-20 w-full max-w-lg flex flex-col items-center text-center py-6 transition-all duration-1000 ${breached ? 'translate-y-0 scale-100' : 'translate-y-4 scale-95'}`}>

                <div className="mb-8 landscape:mb-4 group relative">
                    <div className="absolute inset-[-20px] blur-[40px] md:blur-[60px] transition-all duration-1000 rounded-full opacity-30" style={{ backgroundColor: 'var(--app-accent)' }} />

                    <div className="relative p-10 rounded-full transition-all duration-1000 border-4 border-zinc-950 bg-app-card shadow-[10px_10px_0_black]">
                        <VoidIcon className="w-16 h-16 md:w-24 md:h-24 transition-colors duration-1000 text-app-text" />
                    </div>
                </div>

                <div className="mb-8 landscape:mb-4 flex flex-col items-center">
                    <h1 className="text-5xl md:text-8xl font-black italic uppercase tracking-tighter mb-4 transition-colors duration-1000 text-app-text drop-shadow-[6px_6px_0_black]">
                        THE VOID
                    </h1>

                    <div className="flex items-center justify-center gap-3">
                        <div className="h-1 w-12 bg-zinc-950 transition-colors duration-1000"></div>
                        <p className="font-bold uppercase tracking-[0.6em] text-[8px] md:text-[10px] transition-colors duration-1000" style={{ color: 'var(--app-accent)' }}>
                            {themeMeta.v}_{themeMeta.tag}
                        </p>
                        <div className="h-1 w-12 bg-zinc-950 transition-colors duration-1000"></div>
                    </div>
                </div>

                {!isBootComplete ? (
                    <div className="w-full space-y-4 landscape:space-y-2 max-w-[280px] mx-auto animate-fade-in">
                        <div className="w-full h-4 bg-zinc-950 border-2 border-zinc-900 rounded-sm overflow-hidden p-1 shadow-inner">
                            <div 
                                className="h-full bg-app-accent transition-all duration-200"
                                style={{ width: `${loadingProgress}%` }}
                            />
                        </div>
                        <div className="flex justify-between items-center text-[8px] font-black text-zinc-500 italic tracking-[0.2em]">
                            <span className="truncate max-w-[80%] uppercase">{currentMessage}</span>
                            <span>{Math.floor(loadingProgress)}%</span>
                        </div>
                    </div>
                ) : (
                    <div className="w-full flex flex-col gap-6 landscape:gap-4 animate-fade-in max-w-md items-center main-content-area px-4">
                        <div className="glass-reveal p-1 shadow-2xl overflow-hidden w-full transform -rotate-1">
                            <button 
                                ref={mainButtonRef}
                                onClick={onEnterFeeds}
                                className="group relative w-full py-6 bg-app-text text-app-bg font-black uppercase italic text-lg shadow-xl transition-all active:translate-x-1 active:translate-y-1 flex items-center justify-center gap-4 border-2 border-app-bg outline-none focus:ring-8 focus:ring-app-accent"
                            >
                                <ListIcon className="w-8 h-8" />
                                <span>RECON_INTELLIGENCE</span>
                            </button>
                        </div>

                        <div className="glass-reveal p-1 shadow-2xl overflow-hidden w-full transform rotate-1">
                            <button 
                                onClick={onEnterArcade}
                                className="group w-full py-6 bg-app-card border-2 border-zinc-950 text-app-text font-black uppercase italic text-lg hover:bg-app-bg transition-all active:translate-x-1 active:translate-y-1 flex items-center justify-center gap-4 outline-none focus:ring-8 focus:ring-app-accent"
                            >
                                <ControllerIcon className="w-8 h-8" />
                                <span>ARCADE_QUICK_ACCESS</span>
                            </button>
                        </div>
                    </div>
                )}
            </div>

            {isBootComplete && (
                <div className="fixed bottom-0 left-0 right-0 p-8 md:p-12 pb-[calc(2.5rem+var(--safe-bottom))] flex justify-between items-center z-50 pointer-events-none">
                    <button 
                        onClick={onToggleTheme}
                        className="footer-button group inline-flex items-center gap-3 text-zinc-500 hover:text-app-accent transition-all py-4 px-8 bg-app-card border-4 border-zinc-950 uppercase text-[10px] font-black italic tracking-widest active:translate-x-1 active:translate-y-1 outline-none focus:ring-8 focus:ring-app-accent pointer-events-auto shadow-[6px_6px_0_black] shrink-0"
                    >
                        <PaletteIcon className="w-5 h-5" />
                        <span>UI: {themeLabel}</span>
                    </button>

                    <button 
                        onClick={() => setShowWipeConfirm(true)}
                        className="footer-button group inline-flex items-center justify-center gap-3 text-zinc-500 hover:text-red-500 transition-all py-4 px-8 bg-app-card border-4 border-zinc-950 uppercase text-[10px] font-black italic tracking-widest active:translate-x-1 active:translate-y-1 outline-none focus:ring-8 focus:ring-red-500 pointer-events-auto shadow-[6px_6px_0_black] shrink-0"
                    >
                        <TrashIcon className="w-5 h-5" />
                        <span>PURGE</span>
                    </button>
                </div>
            )}
        </div>
    );
};

export default SplashScreen;

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* THEME 1: NOIR (Signature Default) */
  --app-bg: #050505;
  --app-text: #ffffff;
  --app-accent: #e11d48;
  --app-card: #101012;
  --app-border: rgba(255, 255, 255, 0.1);
  --halo-color: rgba(225, 29, 72, 0.3);
  --void-radius: 1.25rem;
  --comic-ink: #1a1a1a;
  --panel-shadow: 0 10px 30px rgba(0,0,0,0.5);
}

[data-theme='sleek'] {
  --app-bg: #f1f5f9;
  --app-text: #0f172a; /* Dark text for light theme */
  --app-accent: #2563eb;
  --app-card: rgba(255, 255, 255, 0.7);
  --app-border: rgba(15, 23, 42, 0.1);
  --halo-color: rgba(37, 99, 235, 0.2);
  --void-radius: 2rem;
  --panel-shadow: 0 8px 32px rgba(0,0,0,0.05);
}

[data-theme='terminal'] {
  --app-bg: #000000;
  --app-text: #33ff33;
  --app-accent: #33ff33;
  --app-card: #000000;
  --app-border: #33ff33;
  --halo-color: rgba(51, 255, 51, 0.4);
  --void-radius: 0.5rem;
  --panel-shadow: none;
}

[data-theme='brutalist'] {
  --app-bg: #ffffff;
  --app-text: #000000;
  --app-accent: #000000;
  --app-card: #ffffff;
  --app-border: #000000;
  --halo-color: rgba(0, 0, 0, 0.1);
  --void-radius: 0px;
  --panel-shadow: 6px 6px 0px #000000;
}

[data-theme='monochrome-zen'] {
  --app-bg: #0d1b1b; /* Soft Forest/Sage instead of black */
  --app-text: #99f6e4; /* Mint text */
  --app-accent: #2dd4bf;
  --app-card: #132a2a;
  --app-border: rgba(45, 212, 191, 0.2);
  --halo-color: rgba(45, 212, 191, 0.1);
  --void-radius: 1.5rem;
  --panel-shadow: none;
}

[data-theme='y2k'] {
  --app-bg: #004d4d;
  --app-text: #ffffff;
  --app-accent: #ffff00;
  --app-card: #00cccc;
  --app-border: rgba(255, 255, 255, 0.5);
  --void-radius: 3rem;
  --panel-shadow: 0 10px 20px rgba(0,0,0,0.2);
}

[data-theme='comic'] {
  --app-bg: #fffceb; /* Parchment Yellow */
  --app-text: #1a1a1a;
  --app-accent: #ff3e3e;
  --app-card: #ffffff;
  --app-border: #1a1a1a;
  --halo-color: rgba(255, 62, 62, 0.2);
  --void-radius: 0px;
  --panel-shadow: 8px 8px 0px var(--comic-ink);
}

@layer utilities {
  .bg-app-bg { background: var(--app-bg); }
  .bg-app-card { background-color: var(--app-card); }
  .text-app-text { color: var(--app-text); }
  .text-app-accent { color: var(--app-accent); }
  .border-app-accent { border-color: var(--app-accent); }
  .bg-app-accent { background-color: var(--app-accent); }
  .border-app-border { border-color: var(--app-border); }
}

html, body {
  transition: background 0.6s cubic-bezier(0.4, 0, 0.2, 1), color 0.6s ease;
  background: var(--app-bg);
  color: var(--app-text);
  height: 100dvh;
  width: 100%;
}

/* Ensure all cards respect theme radius and overflow */
.void-card {
  overflow: hidden;
  border-radius: var(--void-radius);
  border-color: var(--app-border);
}

/* --- THEME: COMIC BOOK ENGINE --- */
.theme-comic body {
  background-image: 
    radial-gradient(rgba(0,0,0,0.05) 1.5px, transparent 0),
    linear-gradient(rgba(0,0,0,0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0,0,0,0.02) 1px, transparent 1px);
  background-size: 15px 15px, 40px 40px, 40px 40px;
}

.theme-comic .void-card, 
.theme-comic .main-content-area button:not(.footer-button),
.theme-comic .cabinet-poster,
.theme-comic aside,
.theme-comic .bg-app-card {
  border: 4px solid var(--comic-ink) !important;
  box-shadow: var(--panel-shadow) !important;
  background-color: var(--app-card) !important;
}

.theme-comic .text-white, .theme-comic .text-zinc-200, .theme-comic .text-zinc-300 {
  color: var(--app-text) !important;
}

.theme-comic .bg-black, .theme-comic .bg-zinc-950, .theme-comic .bg-zinc-900, .theme-comic .bg-void-950 {
  background-color: var(--app-bg) !important;
}

/* Ben-Day Dots for all imagery */
.theme-comic img {
  filter: contrast(1.1) saturate(1.4);
  mix-blend-mode: multiply;
}

.theme-comic .image-halftone-overlay::after {
  content: "";
  position: absolute;
  inset: 0;
  background-image: radial-gradient(circle, #000 0.8px, transparent 0.8px);
  background-size: 4px 4px;
  opacity: 0.15;
  pointer-events: none;
  z-index: 10;
}

/* --- THEME: LIQUID GLASS ENGINE --- */
.theme-liquid-glass .void-card,
.theme-liquid-glass .main-content-area button:not(.footer-button),
.theme-liquid-glass header {
  backdrop-filter: blur(40px) saturate(180%);
  -webkit-backdrop-filter: blur(40px) saturate(180%);
  background: rgba(255, 255, 255, 0.6);
  border: 1px solid rgba(255, 255, 255, 0.8);
  box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.04);
}

.theme-liquid-glass .text-white, .theme-liquid-glass .text-zinc-200, .theme-liquid-glass .text-zinc-300 {
  color: #0f172a !important;
}

/* --- THEME: BRUTALIST GRID --- */
.theme-brutalist .void-card {
  border: 3px solid black !important;
  box-shadow: 8px 8px 0px black !important;
}

.theme-brutalist .text-zinc-400, .theme-brutalist .text-zinc-500 {
  color: black !important;
  opacity: 1;
}

/* --- GLOBAL ANIMATIONS --- */
.animate-fade-in {
  animation: fadeIn 0.5s cubic-bezier(0.23, 1, 0.32, 1) forwards;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

.nav-underline {
  position: absolute;
  bottom: 0;
  left: 50%;
  width: 0;
  height: 4px;
  background: var(--app-accent);
  transition: all 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
  transform: translateX(-50%);
  border-radius: 4px;
}

*:focus-visible .nav-underline,
button:focus .nav-underline {
  width: 80%;
  box-shadow: 0 0 15px var(--app-accent);
}

.scrollbar-hide::-webkit-scrollbar { display: none; }
.scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }

.cctv-overlay {
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.1) 50%), 
              repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(255, 255, 255, 0.02) 2px, rgba(255, 255, 255, 0.02) 4px);
  pointer-events: none;
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import type { Feed, Folder, Selection, WidgetSettings, Article, ArticleView, Theme } from '../src/App';
import type { SourceType } from './AddSource';
import { SearchIcon, GlobeAltIcon, CpuChipIcon, BeakerIcon, ChartBarIcon, FlagIcon, FireIcon, ControllerIcon, ArrowPathIcon, PaletteIcon, XIcon, RadioIcon } from './icons';
import { resilientFetch } from '../services/fetch';
import { parseRssXml } from '../services/rssParser';
import FeaturedStory from './articles/FeaturedStory';
import MagazineArticleListItem from './articles/MagazineArticleListItem';
import { getCacheCount } from '../services/cacheService';
import FeedOnboarding, { PRESETS } from './FeedOnboarding';

interface MainContentProps {
    feedsToDisplay: Feed[];
    selection: Selection;
    onSelectCategory: (cat: string | null) => void;
    readArticleIds: Set<string>;
    bookmarkedArticleIds: Set<string>;
    articleTags: Map<string, Set<string>>;
    onMarkAsRead: (articleId: string) => void;
    onPurgeBuffer: (articleIds: string[]) => void;
    onMarkAsUnread: (articleId: string) => void;
    onMarkMultipleAsRead: (articleIds: string[]) => void;
    onToggleBookmark: (articleId: string) => void;
    onSetArticleTags: (articleId: string, tags: Set<string>) => void;
    onSearch: (query: string) => void;
    onOpenReader: (article: Article) => void;
    onOpenExternal: (url: string, id: string) => void;
    allFeeds: Feed[];
    onSetFeeds?: (feeds: Feed[]) => void;
    onSetFolders?: (folders: Folder[]) => void;
    refreshKey: number;
    onRefresh: () => void;
    widgetSettings: WidgetSettings;
    articleView: ArticleView;
    theme: Theme;
    onToggleTheme: () => void;
    onOpenSettings: () => void;
    onOpenAddSource: () => void;
    onOpenSidebar: () => void;
    onAddSource: (url: string, type: SourceType) => Promise<void>;
    animationClass: string;
    pageTitle: string;
    initialArticles?: Article[];
    onSetSniffErrorModal: (show: boolean) => void;
    onOpenSearchExplainer?: () => void;
    onOpenIntegrityBriefing?: () => void;
    ambientEnabled: boolean;
    onToggleAmbient: () => void;
}

const ARTICLES_PER_PAGE = 25;
const LOAD_MORE_BATCH = 15;

const CATEGORY_MAP = [
    { id: 'NEWS', icon: <GlobeAltIcon className="w-4 h-4" /> },
    { id: 'TECH', icon: <CpuChipIcon className="w-4 h-4" /> },
    { id: 'SCIENCE', icon: <BeakerIcon className="w-4 h-4" /> },
    { id: 'FINANCE', icon: <ChartBarIcon className="w-4 h-4" /> },
    { id: 'SPORTS', icon: <FlagIcon className="w-4 h-4" /> },
    { id: 'CULTURE', icon: <FireIcon className="w-4 h-4" /> },
    { id: 'GAMING', icon: <ControllerIcon className="w-4 h-4" /> }
];

const MainContent: React.FC<MainContentProps> = (props) => {
    const { selection, onSelectCategory, readArticleIds, bookmarkedArticleIds, onMarkAsRead, onSearch, onOpenReader, onOpenExternal, refreshKey, onRefresh, theme, onToggleTheme, animationClass, allFeeds, onSetFeeds, onSetFolders, initialArticles } = props;

    const [articles, setArticles] = useState<Article[]>(initialArticles || []);
    const [loading, setLoading] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [isSearchActive, setIsSearchActive] = useState(false);
    const [visibleCount, setVisibleCount] = useState(ARTICLES_PER_PAGE);
    const [showOnlyUnread, setShowOnlyUnread] = useState(false);

    useEffect(() => { getCacheCount(); }, [refreshKey]);

    const activeFeeds = useMemo(() => {
        if (!selection.category) return allFeeds;
        const presets = PRESETS.filter(p => p.category === selection.category);
        return presets.map(p => ({
            id: Math.random(), url: p.url, title: p.title, iconUrl: '', folderId: null, category: p.category
        }));
    }, [selection.category, allFeeds]);

    useEffect(() => {
        const fetchRssFeeds = async (targetFeeds: Feed[]) => {
            if (targetFeeds.length === 0) { setArticles([]); return; };
            setLoading(true);
            const promises = targetFeeds.map(feed => 
                resilientFetch(feed.url, { timeout: 10000 })
                    .then(response => response.text())
                    .then(xmlText => {
                        const parsed = parseRssXml(xmlText, feed.title, feed.url);
                        return parsed.map(a => ({ ...a, feedCategory: feed.category || 'GENERAL' }));
                    })
                    .catch(() => [])
            );
            try {
                const results = await Promise.all(promises);
                const allArticles = results.flat();
                allArticles.sort((a, b) => (b.publishedDate?.getTime() || 0) - (a.publishedDate?.getTime() || 0));
                setArticles(Array.from(new Map(allArticles.map(a => [a.id, a])).values()));
            } finally { setLoading(false); }
        };
        fetchRssFeeds(activeFeeds);
    }, [activeFeeds, refreshKey]);

    const filteredArticles = useMemo(() => {
        let result = articles;
        if (selection.type === 'bookmarks') result = result.filter(a => bookmarkedArticleIds.has(a.id));
        else if (selection.type === 'search' && selection.query) {
             const filter = selection.query.toLowerCase();
             result = result.filter(a => a.title.toLowerCase().includes(filter) || a.snippet.toLowerCase().includes(filter) || a.source.toLowerCase().includes(filter));
        }
        if (selection.category) {
            const catLower = selection.category.toLowerCase();
            result = result.filter(a => a.feedCategory === selection.category || a.source.toLowerCase().includes(catLower));
        }
        if (showOnlyUnread) result = result.filter(a => !readArticleIds.has(a.id));
        return result;
    }, [articles, selection, bookmarkedArticleIds, showOnlyUnread, readArticleIds]);

    const handleCategoryClick = (catId: string | null) => {
        onSelectCategory(catId);
    };

    if (allFeeds.length === 0 && selection.type === 'all' && onSetFeeds && onSetFolders) {
        return (
            <main className={`flex-grow overflow-y-auto scrollbar-hide ${animationClass} bg-app-bg pb-40`}>
                <LocalHeader onSearchSubmit={(e: any) => { e.preventDefault(); onSearch(searchQuery); setIsSearchActive(false); }} isSearchActive={isSearchActive} setIsSearchActive={setIsSearchActive} searchQuery={searchQuery} setSearchQuery={setSearchQuery} onToggleTheme={onToggleTheme} onRefresh={onRefresh} selection={selection} handleCategoryClick={handleCategoryClick} theme={theme} />
                <div className="pt-[calc(10rem+var(--safe-top))] md:pt-[calc(11rem+var(--safe-top))]">
                    <FeedOnboarding onComplete={(f, fld) => { onSetFolders(fld); onSetFeeds(f); }} />
                </div>
            </main>
        );
    }

    const latestArticle = filteredArticles.length > 0 ? filteredArticles[0] : null;
    const trendingArticles = filteredArticles.slice(1, 4);
    const rollingNews = filteredArticles.slice(4, visibleCount);

    return (
        <main className={`flex-grow overflow-y-auto scrollbar-hide ${animationClass} bg-app-bg pb-40 scroll-smooth main-content-area`}>
            <LocalHeader 
                onSearchSubmit={(e: any) => { e.preventDefault(); onSearch(searchQuery); setIsSearchActive(false); }} 
                isSearchActive={isSearchActive}
                setIsSearchActive={setIsSearchActive}
                searchQuery={searchQuery} 
                setSearchQuery={setSearchQuery} 
                onToggleTheme={onToggleTheme}
                onRefresh={onRefresh}
                selection={selection} 
                handleCategoryClick={handleCategoryClick} 
                theme={theme}
            />

            <div className="pt-[calc(13.5rem+var(--safe-top))] md:pt-[calc(14.5rem+var(--safe-top))] max-w-[1400px] mx-auto transition-all relative">

                {latestArticle && (
                    <div className="px-4 md:px-6 mb-12">
                        <FeaturedStory 
                            article={latestArticle} 
                            onReadHere={() => onOpenReader(latestArticle)} 
                            onReadExternal={() => onOpenExternal(latestArticle.link, latestArticle.id)} 
                            isRead={readArticleIds.has(latestArticle.id)} 
                        />
                    </div>
                )}

                <div className="px-4 md:px-6 mb-16 grid grid-cols-1 md:grid-cols-3 gap-8 md:gap-10 article-list-grid">
                    {trendingArticles.map(article => (
                        <div key={article.id} className="void-card p-1">
                            <MagazineArticleListItem 
                                article={article} 
                                onMarkAsRead={() => onMarkAsRead(article.id)} 
                                onReadHere={() => onOpenReader(article)} 
                                onReadExternal={() => onOpenExternal(article.link, article.id)} 
                                isRead={readArticleIds.has(article.id)} 
                            />
                        </div>
                    ))}
                </div>

                <div className="px-4 md:px-6 border-t-8 border-app-border pt-16">
                    <div className="flex items-center justify-between mb-12">
                        <div className="flex items-center gap-4">
                            <div className="p-2 bg-app-accent border-4 border-app-border shadow-[4px_4px_0_black]">
                                <RadioIcon className="w-6 h-6 text-white" />
                            </div>
                            <h2 className="font-black text-2xl md:text-5xl text-app-text italic uppercase tracking-tighter leading-none">Rolling_Signals</h2>
                        </div>
                        <UnreadFilterToggle checked={showOnlyUnread} onChange={setShowOnlyUnread} />
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 md:gap-10 article-list-grid">
                        {rollingNews.map(article => (
                            <div key={article.id} className="void-card p-1">
                                <MagazineArticleListItem 
                                    article={article} 
                                    onMarkAsRead={() => onMarkAsRead(article.id)} 
                                    onReadHere={() => onOpenReader(article)} 
                                    onReadExternal={() => onOpenExternal(article.link, article.id)} 
                                    isRead={readArticleIds.has(article.id)} 
                            />
                        </div>
                        ))}
                    </div>

                    {filteredArticles.length > visibleCount && (
                        <div className="mt-20 text-center pb-24">
                            <button 
                                onClick={() => setVisibleCount(c => c + LOAD_MORE_BATCH)} 
                                className="bg-app-text text-app-bg font-black uppercase italic py-6 px-16 text-sm tracking-[0.2em] active:translate-y-1 border-4 border-app-border shadow-[8px_8px_0_black] focus:ring-8 focus:ring-pulse-500 outline-none"
                            >
                                Load_Additional_Clusters
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </main>
    );
};

const LocalHeader: React.FC<any> = ({ onSearchSubmit, searchQuery, setSearchQuery, isSearchActive, setIsSearchActive, onToggleTheme, onRefresh, selection, handleCategoryClick, theme }) => {
    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (isSearchActive) inputRef.current?.focus();
    }, [isSearchActive]);

    const themeLabel = useMemo(() => {
        switch(theme) {
            case 'liquid-glass': return 'REFRACTION';
            case 'bento-grid': return 'BENTO';
            case 'monochrome-zen': return 'ZEN';
            case 'claymorphism': return 'CLAY';
            case 'brutalist': return 'BRUTAL';
            default: return theme.toUpperCase();
        }
    }, [theme]);

    return (
        <div className="fixed top-11 md:top-12 left-0 right-0 z-40 bg-app-bg border-b-4 border-app-border px-4 md:px-8 py-4 flex flex-col md:flex-row items-center gap-4">
            <div className="flex items-center h-12 gap-1.5 overflow-x-auto scrollbar-hide flex-grow w-full md:w-auto sub-header-nav">
                {CATEGORY_MAP.map(cat => (
                    <button 
                        key={cat.id} 
                        onClick={() => handleCategoryClick(cat.id)} 
                        className={`shrink-0 px-3 md:px-4 h-11 border-2 transition-all relative group outline-none uppercase font-black italic text-[10px] tracking-widest shadow-[4px_4px_0_black]
                            ${selection.category === cat.id 
                                ? 'bg-app-accent border-app-border text-white translate-y-1 shadow-none' 
                                : 'bg-app-card border-app-border text-muted hover:text-app-text'}`}
                    >
                        <span className="relative z-10">{cat.id}</span>
                        <div className={`nav-underline ${selection.category === cat.id ? 'w-[70%]' : 'w-0'}`} />
                    </button>
                ))}
            </div>

            <div className="flex items-center gap-2 w-full md:w-auto shrink-0 justify-end">
                <div className="relative shrink-0">
                    {!isSearchActive ? (
                        <button 
                            onClick={() => setIsSearchActive(true)}
                            className="flex items-center gap-2 px-4 h-11 bg-app-card border-4 border-app-border text-[10px] font-black uppercase italic text-muted hover:text-app-text transition-all shadow-[6px_6px_0_black] active:translate-x-1 active:translate-y-1 outline-none shrink-0"
                        >
                            <SearchIcon className="w-4 h-4" />
                            <span>Find</span>
                        </button>
                    ) : (
                        <form onSubmit={onSearchSubmit} className="relative flex items-center gap-3 animate-fade-in">
                            <div className="relative">
                                <SearchIcon className="absolute top-1/2 left-4 -translate-y-1/2 w-4 h-4 text-muted" />
                                <input 
                                    ref={inputRef}
                                    type="text" 
                                    placeholder="SCANNING..." 
                                    value={searchQuery} 
                                    onChange={e => setSearchQuery(e.target.value)} 
                                    onBlur={() => !searchQuery && setIsSearchActive(false)}
                                    className="w-48 md:w-72 bg-app-card border-4 border-app-border py-3 pl-12 pr-6 text-sm uppercase font-black tracking-widest outline-none text-app-text transition-all shadow-[6px_6px_0_black]" 
                                />
                            </div>
                            <button type="button" onClick={() => { setIsSearchActive(false); setSearchQuery(''); }} className="p-3 text-muted hover:text-app-text"><XIcon className="w-5 h-5"/></button>
                        </form>
                    )}
                </div>

                <div className="flex items-center gap-2 shrink-0">
                    <button 
                        onClick={onRefresh}
                        className="p-3 h-11 w-11 flex items-center justify-center bg-app-card border-4 border-app-border text-muted hover:text-app-text transition-all shadow-[4px_4px_0_black] active:translate-x-1 active:translate-y-1"
                        title="Refresh Signals"
                    >
                        <ArrowPathIcon className="w-5 h-5" />
                    </button>

                    <button 
                        onClick={onToggleTheme}
                        className="flex items-center gap-3 px-4 h-11 bg-app-card border-4 border-app-border text-[10px] font-black uppercase italic text-muted hover:text-app-accent transition-all shadow-[4px_4px_0_black] active:translate-x-1 active:translate-y-1 shrink-0"
                        title="Phase Shift"
                    >
                        <PaletteIcon className="w-5 h-5" />
                        <span className="hidden sm:inline">{themeLabel}</span>
                    </button>
                </div>
            </div>
        </div>
    );
};

const UnreadFilterToggle: React.FC<any> = ({ checked, onChange }) => (
    <label className="flex items-center cursor-pointer group bg-app-card px-6 py-3 border-4 border-app-border shadow-[6px_6px_0_black] hover:shadow-[2px_2px_0_black] transition-all active:translate-x-1 active:translate-y-1 outline-none relative">
        <input type="checkbox" className="sr-only" checked={checked} onChange={(e) => onChange(e.target.checked)} />
        <div className={`w-4 h-4 border-4 rounded-sm flex-shrink-0 mr-4 transition-all ${checked ? 'bg-app-accent border-app-border' : 'bg-transparent border-app-border'}`} />
        <span className="text-xs font-black uppercase tracking-widest text-muted group-hover:text-app-text italic">Unread_Only</span>
    </label>
);

export default MainContent;

import React, { useState, useEffect } from 'react';
import type { Article } from '../../src/App';
