  overflow: hidden;
  border-radius: var(--void-radius);
  border-color: var(--app-border);
  background-color: var(--app-card);
}

/* --- THEME: COMIC BOOK ENGINE --- */
.theme-comic body, 
.theme-comic main, 
.theme-comic .bg-void-950, 
.theme-comic .bg-black,
.theme-comic .bg-zinc-950,
.theme-comic .bg-zinc-900,
.theme-comic .bg-void-bg {
  background-color: var(--app-bg) !important;
  background-image: 
    radial-gradient(rgba(0,0,0,0.05) 1.5px, transparent 0),
    linear-gradient(rgba(0,0,0,0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0,0,0,0.02) 1px, transparent 1px) !important;
  background-size: 15px 15px, 40px 40px, 40px 40px !important;
}

.theme-comic .void-card, 
.theme-comic .main-content-area button:not(.footer-button),
.theme-comic .cabinet-poster,
.theme-comic aside,
.theme-comic .bg-app-card {
  border: 4px solid var(--comic-ink) !important;
  box-shadow: var(--panel-shadow) !important;
  background-color: var(--app-card) !important;
}

.theme-comic .text-white, .theme-comic .text-zinc-200, .theme-comic .text-zinc-300, .theme-comic .text-terminal {
  color: var(--app-text) !important;
}

.theme-comic .image-halftone-overlay::after {
  content: "";
  position: absolute;
  inset: 0;
  background-image: radial-gradient(circle, #000 0.8px, transparent 0.8px);
  background-size: 4px 4px;
  opacity: 0.15;
  pointer-events: none;
  z-index: 10;
}

/* --- THEME: LIQUID GLASS ENGINE (APPLE STYLE) --- */
.theme-liquid-glass .void-card,
.theme-liquid-glass .main-content-area button:not(.footer-button),
.theme-liquid-glass header {
  backdrop-filter: blur(25px) saturate(160%) !important;
  -webkit-backdrop-filter: blur(25px) saturate(160%) !important;
  background: rgba(255, 255, 255, 0.35) !important;
  border: 1px solid rgba(255, 255, 255, 0.6) !important;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.05), inset 0 1px 2px rgba(255, 255, 255, 1) !important;
}

/* Enforce black text in modals/cards for Refraction theme */
.theme-liquid-glass .void-card *,
.theme-liquid-glass [role="dialog"] *,
.theme-liquid-glass .text-app-text,
.theme-liquid-glass .text-muted {
  color: #000000 !important;
}

.theme-liquid-glass .bg-app-bg {
  background: radial-gradient(circle at 20% 20%, #f8fafc 0%, #e2e8f0 100%) !important;
}

/* --- THEME: BRUTALIST GRID --- */
.theme-brutalist .void-card {
  border: 3px solid black !important;
  box-shadow: 8px 8px 0px black !important;
}

/* --- GLOBAL ANIMATIONS --- */
.animate-fade-in {
  animation: fadeIn 0.5s cubic-bezier(0.23, 1, 0.32, 1) forwards;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

.nav-underline {
  position: absolute;
  bottom: 0;
  left: 50%;
  width: 0;
  height: 4px;
  background: var(--app-accent);
  transition: all 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
  transform: translateX(-50%);
  border-radius: 4px;
}

*:focus-visible .nav-underline,
button:focus .nav-underline {
  width: 80%;
